/**
 * The time dimension interval.
 *
 * @since 5.0
 */
export interface DimensionInterval<T, K> {
  /**
   * Start of interval.
   *
   * @since 5.0
   */
  min: T;
  /**
   * End of interval.
   *
   * @since 5.0
   */
  max: T;
  /**
   * Interval duration defined by the following properties.
   *
   * @since 5.0
   */
  resolution?: K;
}

/** @since 5.0 */
export interface Duration {
  /**
   * Number of years.
   *
   * @since 5.0
   */
  years: number;
  /**
   * Number of months.
   *
   * @since 5.0
   */
  months: number;
  /**
   * Number of days.
   *
   * @since 5.0
   */
  days: number;
  /**
   * Number of hours.
   *
   * @since 5.0
   */
  hours: number;
  /**
   * Number of minutes.
   *
   * @since 5.0
   */
  minutes: number;
  /**
   * Number of seconds.
   *
   * @since 5.0
   */
  seconds: number;
}

/** @since 5.0 */
export type DimensionExtent<T, K> = T[] | DimensionInterval<T, K>[];

/** @since 5.0 */
export type TimeDimensionExtent = DimensionExtent<Date, Duration | null | undefined>;

/** @since 5.0 */
export interface Dimension<T> {
  /**
   * Available value(s) for the time dimension.
   *
   * @since 5.0
   */
  extent: T;
  /**
   * Default value(s) for the time dimension.
   * The default value will be used if the request does not include a value for the time dimension.
   *
   * @since 5.0
   */
  default?: T;
  /**
   * Indicates whether multiple values of the dimension may be requested.
   *
   * @since 5.0
   */
  multipleValues?: boolean;
  /**
   * Indicates whether the nearest value of the dimension will be returned in response to a request for a nearby value.
   *
   * @since 5.0
   */
  nearestValue?: boolean;
}

/**
 * Generic dimension information.
 *
 * @since 5.0
 */
export interface GenericDimension {
  /**
   * Name of dimensional axis.
   *
   * @since 5.0
   */
  name: string;
}

/**
 * Elevation dimension information.
 *
 * @since 5.0
 */
export interface ElevationDimension {
  /**
   * Name of dimensional axis.
   *
   * @since 5.0
   */
  name: "elevation";
}

/**
 * Time dimension information. For example, the WMS service might be published to show hourly weather information.
 * The TimeDimension can be used to update [View.timeExtent](https://developers.arcgis.com/javascript/latest/references/core/views/View/#timeExtent),
 * [WMSLayer.timeExtent](https://developers.arcgis.com/javascript/latest/references/core/layers/WMSLayer/#timeExtent), or to configure a [TimeSlider](https://developers.arcgis.com/javascript/latest/references/core/widgets/TimeSlider/) widget.
 *
 * @since 5.0
 */
export interface TimeDimension extends Omit<Dimension<TimeDimensionExtent>, "unitSymbol"> {
  /**
   * Name of dimensional axis.
   *
   * @since 5.0
   */
  name: "time";
  /**
   * Units of dimensional axis.
   *
   * @since 5.0
   */
  units: "ISO8601";
}

/** @since 5.0 */
export type WMSDimension = ElevationDimension | GenericDimension | TimeDimension;